    91→    modalizeRef?.current?.close?.();
    92→    eventSelectContent({
    93→      content_type: 'cta',
    94→      content_id: 'criar_cartao_virtual',
    95→      location_1: 'autosservico',
    96→      location_2: 'spmais',
    97→      location_3: 'cartao_virtual_ativar',
    98→    });
    99→    debounceModal(() => setUiState((prev) => ({ ...prev, isModalVisible: true })));
   100→  }, []);
   101→
   102→  useImperativeHandle(
   103→    ref,
   104→    () => ({
   105→      open: (type) => {
   106→        setUiState((prev) => ({ ...prev, cardsToShow: type || DEFAULT_CARDS_TYPE_TO_SHOW }));
   107→        modalizeRef.current?.open?.();
   108→      },
   109→      close: () => {
   110→        modalizeRef.current?.close?.();
   111→      },
   112→      openCreateVirtualCardModal: () => {
   113→        handleCreateVirtualCardPress();
   114→      },
   115→    }),
   116→    [handleCreateVirtualCardPress]
   117→  );
   118→
   119→  useEffect(() => {
   120→    if (uiState.activeCardNumber && uiState.activeCardTrigger > 0) {
   121→      refConfirmedReceivedCard.current?.open?.();
   122→    }
   123→  }, [uiState.activeCardTrigger]);
   124→
   125→  const cards = productsReducer?.data?.[0]?.Cartoes;
   126→
   127→  const lastCards =
   128→    cards?.length >= 2
   129→      ? cards?.sort((a, b) => {
   130→          if (moment(a.DataAberturaCartao).isAfter(b.DataAberturaCartao)) {
   131→            return -1;
   132→          }
   133→          if (moment(a.DataAberturaCartao).isBefore(b.DataAberturaCartao)) {
   134→            return 1;
   135→          }
   136→          if (moment(a.DataAtivacao).isAfter(b.DataAtivacao)) {
   137→            return -1;
   138→          }
   139→          if (moment(a.DataAtivacao).isBefore(b.DataAtivacao)) {
   140→            return 1;
   141→          }
   142→          return 0;
   143→        })
   144→      : cards;
   145→
   146→  const getCardTypeLabel = (obj: ProductCard) => {
   147→    if (accountReducer?.card?.cardNumber?.endsWith(obj.NrCartao.slice(-4))) {
   148→      return CardLabel.TAG;
   149→    }
   150→
   151→    if (obj.TipoBloqueio === 'XW') {
   152→      return CardLabel.ACTIVATE_CARD;
   153→    }
   154→
   155→    const isDeliveryFailed =
   156→      (obj.TipoBloqueio === 'VW' && obj.MotivoCancelamento === '112') ||
   157→      (obj.TipoBloqueio === 'XS' && obj.MotivoCancelamento === '993');
   158→
   159→    if (isDeliveryFailed) {
   160→      return CardLabel.DELIVERY_FAILED;
   161→    }
   162→
   163→    const isCancelled =
   164→      obj.Status?.toLowerCase() === 'cancelado' ||
   165→      (obj.Bloqueio &&
   166→        getIsCanceledCard({
   167→          cancellationReason: obj.MotivoCancelamento,
   168→          blockType: obj.TipoBloqueio,
   169→        }));
   170→
   171→    if (isCancelled) {
   172→      return CardLabel.CANCELED;
   173→    }
   174→
   175→    if (obj.MotivoCancelamento !== '356' && obj.Bloqueio && !obj.Virtual && !isCancelled) {
   176→      return CardLabel.BLOCKED;
   177→    }
   178→
   179→    return obj.Virtual ? CardLabel.VIRTUAL : CardLabel.PHYSICAL;
   180→  };
   181→
   182→  const cardsMap: CardsMap = useMemo(
   183→    () =>
   184→      lastCards?.reduce(
   185→        (acc, obj, index) => {
   186→          const typeCard = getCardTypeLabel(obj);
   187→          const payload: Card = {
   188→            id: index,
   189→            numberCard: obj.NrCartao.slice(-4),
   190→            name: obj.NomePortador,
   191→            bloqueio: obj.Bloqueio,
   192→            typeCard,
   193→            tipoBloqueio: obj.TipoBloqueio,
   194→            motivoCancelamento: obj.MotivoCancelamento,
   195→            Embossado: obj.Embossado,
   196→          };
   197→
   198→          if (
   199→            obj.Virtual &&
   200→            typeCard !== CardLabel.TAG &&
   201→            uiState.cardsToShow.includes(CardType.VIRTUAL)
   202→          ) {
   203→            acc.virtual.push(payload);
   204→            return acc;
   205→          }
   206→          if (CardLabel.TAG === typeCard && uiState.cardsToShow.includes(CardType.TAG)) {
   207→            acc.tag.push(payload);
   208→            return acc;
   209→          }
   210→
   211→          if (obj.Titular && uiState.cardsToShow.includes(CardType.PHYSICAL)) {
   212→            acc.physical.push(payload);
   213→            return acc;
   214→          }
   215→
   216→          if (!obj.Titular && !obj.Virtual && uiState.cardsToShow.includes(CardType.ADDITIONAL)) {
   217→            acc.additional.push(payload);
   218→          }
   219→          return acc;
   220→        },
   221→        {
   222→          [CardType.PHYSICAL]: [],
   223→          [CardType.VIRTUAL]: [],
   224→          [CardType.ADDITIONAL]: [],
   225→          [CardType.TAG]: [],
   226→        } as Record<CardType, Card[]>
   227→      ),
   228→    [productsReducer?.data?.[0]?.Cartoes, uiState.cardsToShow]
   229→  );
   230→
   231→  const filterPhysicalCards = useMemo(() => {
   232→    const physicalCards =
   233→      cardsMap?.physical?.length > 2
   234→        ? [cardsMap?.physical[0], cardsMap?.physical[1]]
   235→        : cardsMap?.physical;
   236→
   237→    if (!physicalCards?.length) {
   238→      return [];
   239→    }
   240→
   241→    const activatedCard = physicalCards?.find((card) => !card.bloqueio);
   242→    const cardToBeActivated = physicalCards?.find(
   243→      (card) => card.typeCard === CardLabel.ACTIVATE_CARD
   244→    );
   245→    const canceledCard = physicalCards?.find((card) => card.typeCard === CardLabel.CANCELED);
   246→    const failedToDeliver = physicalCards?.find(
   247→      (card) => card.typeCard === CardLabel.DELIVERY_FAILED
   248→    );
   249→    const hasTwoCancelled = physicalCards?.every((card) => card.typeCard === CardLabel.CANCELED);
   250→
   251→    if (failedToDeliver && physicalCards?.length < 2) {
   252→      return [failedToDeliver];
   253→    }
   254→
   255→    if (activatedCard) {
   256→      return [activatedCard];
   257→    }
   258→
   259→    if (canceledCard && cardToBeActivated) {
   260→      return [canceledCard, cardToBeActivated];
   261→    }
   262→
   263→    if (cardToBeActivated) {
   264→      return physicalCards;
   265→    }
   266→
   267→    if (hasTwoCancelled) {
   268→      return [physicalCards[0]];
   269→    }
   270→
   271→    if (canceledCard) {
   272→      return physicalCards?.filter(
   273→        (card) =>
   274→          card.typeCard !== CardLabel.DELIVERY_FAILED && card.typeCard !== CardLabel.CANCELED
   275→      );
   276→    }
   277→
   278→    return physicalCards?.filter((card) => card.typeCard !== CardLabel.DELIVERY_FAILED);
   279→  }, [cardsMap]);
   280→
   281→  const physicalCard = filterPhysicalCards?.filter((pCard) => pCard?.id !== undefined);
   282→
   283→  const handleCardDetail: MyCardsViewProps['handleCardDetail'] = ({
   284→    type,
   285→    cardNumber,
   286→    physicalCode,
   287→    analytics,
   288→    isAdditionalCard,
   289→  }) => {
   290→    switch (type) {
   291→      case CardLabel.VIRTUAL:
   292→        navigation.navigate('DetailVirtualCardRecurrent', {
   293→          numberCard: cardNumber,
   294→          analytics,
   295→        } as unknown as NumberCardVirtualRecurrentRouteParams & AnalyticsProps);
   296→        modalizeRef?.current?.close?.();
   297→        break;
   298→      case CardLabel.TAG:
   299→        handleTagDetail(cardNumber, analytics);
   300→        break;
   301→      case CardLabel.ACTIVATE_CARD:
   302→        modalizeRef?.current?.close?.();
   303→        debounceModal(() => setUiState((prev) => ({ 
   304→          ...prev, 
   305→          activeCardNumber: cardNumber,
   306→          activeCardTrigger: prev.activeCardTrigger + 1
   307→        })));
   308→        break;
   309→      default:
   310→        navigation.navigate('DetailPhysicalCard', {
   311→          numberCard: cardNumber,
   312→          physicalCode,
   313→          analytics,
   314→          isAdditionalCard,
   315→        });
   316→        modalizeRef?.current?.close?.();
   317→        break;
   318→    }
   319→  };
   320→
   321→  const handleTagDetail = (numberCard: string, analytics?: AnalyticsProps) => {
   322→    navigation.navigate('TagDetail', {
   323→      numberCard,
   324→      analytics,
   325→    } as unknown as NumberCardVirtualRecurrentRouteParams & AnalyticsProps);
   326→  };
   327→
   328→  const getProducts = useCallback(() => {
   329→    setTimeout(() => {
   330→      productRequest(false, ({ statusCode }) => {
   331→        if (statusCode === 200) {
   332→          setUiState((prev) => ({ ...prev, newCardNumber: true }));
   333→        }
   334→        if (statusCode === 504) {
   335→          getProducts();
   336→        }
   337→      });
   338→    }, 1000);
   339→  }, []);
   340→
   341→  const handleCreateVirtualCard = () => {
   342→    setUiState((prev) => ({ ...prev, isModalVisible: false }));
   343→    putVirtualCard({ CPF: customerReducer.document, Conta: productsReducer.data[0]?.Conta }, () =>
   344→      getProducts()
   345→    );
   346→  };
   347→
   348→  const handleGoToCardDetail = () => {
   349→    eventSelectContent({
   350→      content_type: 'cta',
   351→      content_id: 'acesse_cartao_virtual',
   352→      location_1: 'autosservico',
   353→      location_2: 'spmais',
   354→      location_3: 'cartao_virtual_ativar_sucesso',
   355→    });
   356→    const cardNumberNavigation = productsReducer?.data?.[0]?.Cartoes?.find((item) => {
   357→      return item.NrCartao.endsWith(virtualCardReducer.cardNumber.slice(-4));
   358→    });
   359→
   360→    if (!cardNumberNavigation) {
   361→      return;
   362→    }
   363→
   364→    navigation.navigate('DetailVirtualCardRecurrent', {
   365→      numberCard: cardNumberNavigation?.NrCartao?.substring(
   366→        cardNumberNavigation.NrCartao.length,
   367→        12
   368→      ),
   369→      analytics: {
   370→        screen_name: 'spmais',
   371→        screen_class: 'cartao_virtual_ativar_sucesso',
   372→        screen_bussines: 'autosservico',
   373→        screen_info: {
   374→          location_1: 'autosservico',
   375→          location_2: 'spmais',
   376→          location_3: 'cartao_virtual_ativar_sucesso',
   377→        },
   378→      },
   379→    });
   380→
   381→    setUiState((prev) => ({ ...prev, newCardNumber: false }));
   382→  };
   383→
   384→  const handleNavigateToLiveness = () => {
   385→    setUiState((prev) => ({ ...prev, activeCardNumber: null }));
   386→    refConfirmedReceivedCard.current?.close?.();
   387→    if (uiState.activeCardNumber) {
   388→      navigation.navigate('CardValidation', {
   389→        lastFourNumbers: uiState.activeCardNumber,
   390→        from: 'fintechHome',
   391→        analytics: {
   392→          screen_name: 'spmais',
   393→          screen_class: 'meus_cartoes',
   394→          screen_bussines: 'autosservico',
   395→          screen_info: {
   396→            location_1: 'autosservico',
   397→            location_2: 'spmais',
   398→            location_3: 'meus_cartoes',
   399→          },
   400→        },
   401→      });
   402→    }
   403→  };
   404→
   405→  const handleCloseConfirmReceivedCard = () => {
   406→    setUiState((prev) => ({ ...prev, activeCardNumber: null }));
   407→    refConfirmedReceivedCard.current?.close?.();
   408→  };
   409→
   410→  const handleCardError = useCallback(() => {
   411→    getProducts();
   412→    cleanVirtualCard();
   413→  }, []);
   414→
   415→  const modalHeight = useMemo(() => {
   416→    const height = cards?.length > 6 ? 0.65 : cards?.length > 3 ? 0.55 : 0.4;
   417→
   418→    return Math.round(HEIGHT_DIMENSION * height);
   419→  }, [cards?.length]);
   420→
   421→  const CardUtils: TCardUtils = {
   422→    getTagLabelText: (item: CardLabel, blocked = false) => {
   423→      if (blocked) {
   424→        return 'Bloqueado';
   425→      }
   426→
   427→      if (item === CardLabel.VIRTUAL) {
   428→        return undefined;
   429→      }
   430→
   431→      return item;
   432→    },
   433→    getTagLabelTextPhysical: (item: CardLabel) => {
   434→      if ([CardLabel.PHYSICAL, CardLabel.VIRTUAL, CardLabel.TAG].includes(item)) {
   435→        return undefined;
   436→      }
   437→
   438→      if (item === CardLabel.ACTIVATE_CARD) {
   439→        return 'Ativar';
   440→      }
   441→
   442→      return item;
   443→    },
   444→    failedOrCancelled: (
   445→      item: CardLabel,
   446→      blocked = false,
   447→      blockedTypes = [CardLabel.CANCELED, CardLabel.BLOCKED, CardLabel.DELIVERY_FAILED]
   448→    ) => blockedTypes.includes(item) || blocked,
   449→    getTagLabelType: (item: CardLabel, blocked = false) =>
   450→      CardUtils.failedOrCancelled(item) || blocked ? 'error' : 'highlight',
   451→    getIconName: (item: CardLabel) =>
   452→      CardUtils.failedOrCancelled(item) ? 'icon-card-block' : 'icon-card',
   453→    getColor: (item: CardLabel, blocked = false) =>
   454→      CardUtils.failedOrCancelled(item) || blocked ? 'INTENSE_COLOR_02' : 'BRAND_COMPLEMENT_01',
   455→    getDescription: (item: Card, hideNumberCard = false) =>
   456→      `${capitalizeEachWord(item?.name)} ${
   457→        item?.typeCard !== 'Ativar cartão' && !hideNumberCard ? `- ${item?.numberCard}` : ''
   458→      }`,
   459→  };
   460→
   461→  const getVirtualCardStatus = useCallback(() => {
   462→    if (cardsMap?.virtual?.length === 0) {
   463→      return {
   464→        hasVirtualCard: false,
   465→        isBlocked: false,
   466→        tagText: 'Ativar',
   467→        tagType: 'highlight' as const,
   468→        onPress: handleCreateVirtualCardPress,
   469→        description: '',
   470→      };
   471→    }
   472→    if (cardsMap?.virtual?.some((card) => card.bloqueio)) {
   473→      return {
   474→        hasVirtualCard: true,
   475→        isBlocked: true,
   476→        tagText: 'Bloqueado',
   477→        tagType: 'error' as const,
   478→        onPress: () => {
   479→          const blockedCard = cardsMap?.virtual?.find((card) => card.bloqueio);
   480→          if (blockedCard) {
   481→            handleCardDetail({
   482→              type: CardLabel.VIRTUAL,
   483→              cardNumber: blockedCard.numberCard,
   484→              analytics: {
   485→                analytics: {
   486→                  screen_name: 'spmais',
   487→                  screen_class: 'meus_cartoes',
   488→                  screen_bussines: 'autosservico',
   489→                  screen_info: {
   490→                    location_1: 'autosservico',
   491→                    location_2: 'spmais',
   492→                    location_3: 'meus_cartoes',
   493→                  },
   494→                },
   495→              },
   496→            });
   497→          }
   498→        },
   499→        description: CardUtils.getDescription(cardsMap?.virtual?.[0]),
   500→      };
   501→    }
   502→    return {
   503→      hasVirtualCard: true,
   504→      isBlocked: false,
   505→      tagText: '',
   506→      tagType: 'neutral' as const,
   507→      onPress: () => {
   508→        const activeCard = cardsMap?.virtual?.[0];
   509→        if (activeCard) {
   510→          handleCardDetail({
   511→            type: CardLabel.VIRTUAL,
   512→            cardNumber: activeCard.numberCard,
   513→            analytics: {
   514→              analytics: {
   515→                screen_name: 'spmais',
   516→                screen_class: 'meus_cartoes',
   517→                screen_bussines: 'autosservico',
   518→                screen_info: {
   519→                  location_1: 'autosservico',
   520→                  location_2: 'spmais',
   521→                  location_3: 'meus_cartoes',
   522→                },
   523→              },
   524→            },
   525→          });
   526→        }
   527→      },
   528→      description: CardUtils.getDescription(cardsMap?.virtual?.[0]),
   529→    };
   530→  }, [productsReducer?.data, handleCardDetail, handleCreateVirtualCardPress]);
   531→
   532→  const virtualCardStatus = getVirtualCardStatus();
   533→
   534→  const viewCards = useMemo(() => {
   535→    if (virtualCardReducer.isLoading || productsReducer.isLoading) {
   536→      return <LoadingModal text="Aguarde..." />;
   537→    }
   538→
   539→    if (uiState.newCardNumber) {
   540→      return (
   541→        <Box height="100%" width={width} index={999}>
   542→          <Success
   543→            onPress={() => {
   544→              handleGoToCardDetail();
   545→            }}
   546→            buttonProps={{ text: 'Acesse seu cartão virtual' }}
   547→            title="Seu cartão virtual foi criado"
   548→            subTitle="Para suas comprar online com mais segurança o CVV muda automaticamente a cada 1h."
   549→          />
   550→        </Box>
   551→      );
   552→    }
   553→
   554→    if (virtualCardReducer?.isError && cardsMap?.virtual?.length === 0) {
   555→      return (
   556→        <Box height="100%" position="absolute" width={width} index={999}>
   557→          <ApiError onPress={handleCardError} isLoading={virtualCardReducer.isLoading} />
   558→        </Box>
   559→      );
   560→    }
   561→
   562→    const navigateToAdditionalCard = () => {
   563→      modalizeRef.current?.close?.();
   564→      navigation.navigate('AdditionalCardInstructions');
   565→    };
   566→
   567→    return (
   568→      <>
   569→        <ConfirmReceivedCard
   570→          refConfirmedReceivedCard={refConfirmedReceivedCard as PropsModalizeRef}
   571→          onPressFirstButtonConfirmReceivedCard={handleNavigateToLiveness}
   572→          onPressSecondButtonConfirmReceivedCard={handleCloseConfirmReceivedCard}
   573→        />
   574→        <ModalTwoButton
   575→          title="Deseja criar seu cartão virtual?"
   576→          typeButtonSecondary="secundarySmall"
   577→          typeButtonPrimary="primarySmall"
   578→          visible={uiState.isModalVisible}
   579→          textButtonPrimary="Sim"
   580→          textButtonSecondary="Não"
   581→          onClose={() => setUiState((prev) => ({ ...prev, isModalVisible: false }))}
   582→          onPressPrimaryButton={handleCreateVirtualCard}
   583→          onPressSecondaryButton={() => setUiState((prev) => ({ ...prev, isModalVisible: false }))}
   584→        />
   585→        <BackDropBottom
   586→          modalizeRef={modalizeRef}
   587→          modalHeight={modalHeight}
   588→          HeaderComponent={<Box />}
   589→        >
   590→          <MyCardsView
   591→            handleCardDetail={handleCardDetail}
   592→            physicalCard={physicalCard}
   593→            additionalCards={cardsMap?.additional}
   594→            cardsToShow={uiState.cardsToShow}
   595→            setModalVisible={(value) => {
   596→              const newValue = typeof value === 'function' ? value(uiState.isModalVisible) : value;
   597→              setUiState((prev) => ({ ...prev, isModalVisible: newValue }));
   598→            }}
   599→            canRequestAdditionalCard={!hasReachedMaxAdditionalCards}
   600→            navigateToAdditionalCard={navigateToAdditionalCard}
   601→            isLoading={
   602→              productsReducer.isLoading ||
   603→              virtualCardReducer.isLoading ||
   604→              productsReducer.isLoadingFromHome
   605→            }
   606→            cardUtils={CardUtils}
   607→            virtualCardStatus={virtualCardStatus}
   608→            isAdditionalCardFlowEnabled={isAdditionalCardFlowEnabled}
   609→            widthSkeleton={width}
   610→          />
   611→        </BackDropBottom>
   612→      </>
   613→    );
   614→  }, [
   615→    productsReducer,
   616→    uiState,
   617→    cardsMap,
   618→    virtualCardReducer,
   619→    filterPhysicalCards,
   620→    handleCardError,
   621→    handleCreateVirtualCardPress,
   622→    width,
   623→  ]);
   624→
   625→  return viewCards;
   626→};
   627→
   628→export const mapStateToProps = ({
   629→  productsReducer,
   630→  customerReducer,
   631→  virtualCardReducer,
   632→  accountReducer,
   633→}: AppReducers) => ({
   634→  productsReducer,
   635→  customerReducer,
   636→  virtualCardReducer,
   637→  accountReducer,
   638→});
   639→
   640→export const mapDispatchToProps = (dispatch: Dispatch) => {
   641→  return bindActionCreators(
   642→    {
   643→      ...productsAction,
   644→      ...virtualCardActions,
   645→    },
   646→    dispatch
   647→  );
   648→};
   649→
   650→const MyCardsWithRef = forwardRef(MyCards);
   651→
   652→const UnconnectedMyCards = MyCards;
   653→;
   654→
   655→export default connect(mapStateToProps, mapDispatchToProps, null, {
   656→  forwardRef: true,
   657→})(MyCardsWithRef);
   658→

